using System.Collections;
using UnityEngine;

/// <summary>
/// Executor de efeitos de status num inimigo (P7 — consome
/// EnemyItemInteractionConfig/EnemyStatusEffect, que estavam configuráveis mas
/// sem executor). Usado por itens do player (PlayerItemUser), pelo Rugido
/// (RoarAbility) e por qualquer mecânica futura.
///
/// Respeita as fraquezas e imunidades do EnemyData:
/// - Sleep → canBePutToSleep (acorda ao tomar dano);
/// - Freeze → canBeFrozen (tinge o sprite de azul);
/// - Trap → canBeGroundPinned;
/// - Stun → canBeStunned;
/// - LoseTarget → sempre permitido (perde o alvo e volta para casa);
/// - Knockback → itemInteractions.affectedByKnockbackItems + canBePushed;
/// - immuneEffects/immuneItems → bloqueiam tudo.
///
/// Sleep/Freeze/Trap/Stun usam o estado Atordoado (EnemyState) com duração e
/// feedback próprios. <see cref="ApplyItem"/> resolve o efeito de um ItemData:
/// primeiro "otherItemEffects", depois os itens do GDD por itemId
/// (flor_do_silencio, resina_antiga, po_dourado, cristal_de_gelo,
/// bolha_de_coral) ligados às flags can*From*.
/// </summary>
[DisallowMultipleComponent]
[RequireComponent(typeof(EnemyController))]
public class EnemyStatusEffectReceiver : MonoBehaviour
{
    // IDs dos itens do GDD (usar nos assets ItemData correspondentes, ou ligar via otherItemEffects).
    public const string SilenceFlowerId = "flor_do_silencio";
    public const string AncientResinId = "resina_antiga";
    public const string GoldenDustId = "po_dourado";
    public const string IceCrystalId = "cristal_de_gelo";
    public const string CoralBubbleId = "bolha_de_coral";

    [Header("Durações por Defeito (segundos)")]
    public float sleepDuration = 5f;
    public float freezeDuration = 3f;
    public float trapDuration = 2f;
    public float stunDuration = 1f;

    [Header("Feedback")]
    [Tooltip("Tinta aplicada ao sprite enquanto congelado.")]
    public Color freezeTint = new Color(0.6f, 0.8f, 1f, 1f);

    private EnemyController _controller;
    private EnemyHealth _health;
    private SpriteRenderer _sprite;
    private Color _baseColor;

    private Coroutine _effectRoutine;
    private EnemyState _stateBeforeEffect;
    private bool _sleeping;

    // Resina Antiga (Tarefa "Itens Consumíveis"): velocidade adicional aplicada
    // enquanto o efeito de Trap estiver activo (puxão para baixo em inimigos
    // voadores, afundamento em aquáticos). Vector2.zero = sem efeito extra
    // (comportamento normal de terrestre: apenas imobilizado).
    private Vector2 _pullVelocity;

    private void Awake()
    {
        _controller = GetComponent<EnemyController>();
        _health = GetComponent<EnemyHealth>();
        _sprite = _controller.SpriteRenderer;
        if (_sprite != null) _baseColor = _sprite.color;
    }

    private void OnEnable()
    {
        if (_health != null) _health.OnDamaged += HandleDamaged;
    }

    private void OnDisable()
    {
        if (_health != null) _health.OnDamaged -= HandleDamaged;
    }

    /// <summary>Acordar ao tomar dano (Sleep).</summary>
    private void HandleDamaged(int amount, int currentHealth)
    {
        if (_sleeping) CancelEffect();
    }

    /// <summary>
    /// Aplica um efeito de status, respeitando fraquezas/imunidades. Devolve
    /// true se o efeito foi aplicado. "duration" &lt;= 0 usa a duração por defeito.
    /// </summary>
    public bool ApplyEffect(EnemyStatusEffect effect, float duration = 0f, Vector2? origin = null, float force = 0f)
    {
        if (_controller.IsTerminal) return false;

        var data = _controller.Data;
        var weaknesses = data != null ? data.weaknesses : null;
        var items = data != null ? data.itemInteractions : null;

        // Imunidade total ao efeito.
        if (items != null && items.immuneEffects != null && items.immuneEffects.Contains(effect)) return false;

        switch (effect)
        {
            case EnemyStatusEffect.Sleep:
                // GDD: Flor do Silêncio não funciona em bosses (imunidade universal,
                // independentemente de canBePutToSleep ou immuneEffects mal configurados).
                if (_controller.GetComponent<BossController>() != null) return false;
                if (weaknesses == null || !weaknesses.canBePutToSleep) return false;
                StartStunLike(duration > 0f ? duration : sleepDuration, sleeping: true);
                return true;

            case EnemyStatusEffect.Freeze:
                if (weaknesses == null || !weaknesses.canBeFrozen) return false;
                StartStunLike(duration > 0f ? duration : freezeDuration, frozen: true);
                return true;

            case EnemyStatusEffect.Trap:
                if (weaknesses == null || !weaknesses.canBeGroundPinned) return false;
                StartStunLike(duration > 0f ? duration : trapDuration);
                return true;

            case EnemyStatusEffect.Stun:
                if (weaknesses == null || !weaknesses.canBeStunned) return false;
                StartStunLike(duration > 0f ? duration : stunDuration);
                return true;

            case EnemyStatusEffect.LoseTarget:
                _controller.Target = null;
                if (_controller.State == EnemyState.Perseguindo || _controller.State == EnemyState.Alerta)
                    _controller.SetState(EnemyState.VoltandoParaCasa);
                return true;

            case EnemyStatusEffect.Knockback:
                if (items != null && !items.affectedByKnockbackItems) return false;
                if (weaknesses != null && !weaknesses.canBePushed) return false;
                ApplyKnockback(origin ?? (Vector2)transform.position + Vector2.left, force > 0f ? force : 6f);
                return true;

            default:
                return false;
        }
    }

    /// <summary>
    /// Aplica o efeito configurado para "item" neste inimigo: primeiro
    /// "otherItemEffects", depois os itens do GDD por itemId. Devolve true se
    /// algum efeito foi aplicado.
    /// </summary>
    public bool ApplyItem(ItemData item, Vector2? origin = null)
    {
        if (item == null || _controller.Data == null) return false;

        var config = _controller.Data.itemInteractions;
        if (config == null) return false;

        // Imune a este item específico.
        if (config.immuneItems != null && config.immuneItems.Contains(item)) return false;

        // 1. Mapeamento explícito (qualquer item global/regional).
        if (config.otherItemEffects != null)
        {
            foreach (var entry in config.otherItemEffects)
            {
                if (entry != null && entry.item == item)
                    return ApplyEffect(entry.effect, 0f, origin);
            }
        }

        // 2. Itens do GDD por itemId + flags.
        switch (item.itemId)
        {
            case SilenceFlowerId:
                return config.canSleepFromSilenceFlower && ApplyEffect(EnemyStatusEffect.Sleep, item.sleepDuration, origin);

            case AncientResinId:
                return config.canBeTrappedByAncientResin && ApplyAncientResin(item, origin);

            case GoldenDustId:
                return config.losesTargetFromGoldenDust && ApplyEffect(EnemyStatusEffect.LoseTarget, 0f, origin);

            case IceCrystalId:
                return config.canBeFrozenByIceCrystal && ApplyEffect(EnemyStatusEffect.Freeze, item.freezeDuration, origin);

            case CoralBubbleId:
                // Bolha de Coral (Tarefa "Itens Consumíveis"): correcção de design —
                // este item é um buff exclusivo do player (imunidade temporária a
                // correntes de água, ver PlayerConsumableEffects/WaterMotor2D), não
                // um efeito sobre inimigos. "affectedByCoralBubble"/Stun deixou de
                // ser usado aqui.
                return false;

            default:
                return false;
        }
    }

    /// <summary>
    /// Resina Antiga (Tarefa "Itens Consumíveis"): aplica o efeito de Trap
    /// (respeita canBeGroundPinned/immuneEffects, via <see cref="ApplyEffect"/>)
    /// e, adicionalmente, configura um "puxão" contínuo conforme o ambiente do
    /// inimigo enquanto o efeito durar:
    /// - Terrestre (padrão): apenas imobilizado (sem puxão).
    /// - Voador (<see cref="EnemyStats.isFlying"/>): puxado para baixo a
    ///   <see cref="ItemData.resinFlyingPullSpeed"/> unidades/seg.
    /// - Aquático (<see cref="EnemyWaterConfig.canSwim"/> ou
    ///   <see cref="EnemyWaterConfig.canDive"/>): afunda a
    ///   <see cref="ItemData.resinAquaticSinkSpeed"/> unidades/seg.
    /// </summary>
    private bool ApplyAncientResin(ItemData item, Vector2? origin)
    {
        var data = _controller.Data;
        float duration = item.resinDuration > 0f ? item.resinDuration : trapDuration;

        if (!ApplyEffect(EnemyStatusEffect.Trap, duration, origin)) return false;

        var stats = data != null ? data.stats : null;
        var water = data != null ? data.water : null;

        if (stats != null && stats.isFlying && item.resinFlyingPullSpeed > 0f)
            _pullVelocity = Vector2.down * item.resinFlyingPullSpeed;
        else if (water != null && (water.canSwim || water.canDive) && item.resinAquaticSinkSpeed > 0f)
            _pullVelocity = Vector2.down * item.resinAquaticSinkSpeed;
        else
            _pullVelocity = Vector2.zero;

        return true;
    }

    /// <summary>Aplica o "puxão" da Resina Antiga (ver <see cref="ApplyAncientResin"/>) enquanto o inimigo estiver Atordoado por este efeito.</summary>
    private void FixedUpdate()
    {
        if (_pullVelocity == Vector2.zero) return;
        if (_controller.State != EnemyState.Atordoado) return;
        if (_controller.Rb == null) return;

        _controller.Rb.MovePosition(_controller.Rb.position + _pullVelocity * Time.fixedDeltaTime);
    }

    /// <summary>Cancela o efeito em curso (acordar/descongelar antecipado).</summary>
    public void CancelEffect()
    {
        if (_effectRoutine != null)
        {
            StopCoroutine(_effectRoutine);
            _effectRoutine = null;
        }

        EndStunLike();
    }

    private void StartStunLike(float duration, bool sleeping = false, bool frozen = false)
    {
        if (_effectRoutine != null) StopCoroutine(_effectRoutine);
        else _stateBeforeEffect = _controller.State == EnemyState.Atordoado ? EnemyState.Perseguindo : _controller.State;

        _sleeping = sleeping;

        if (_controller.Rb != null) _controller.Rb.linearVelocity = Vector2.zero;
        _controller.SetState(EnemyState.Atordoado);

        if (frozen && _sprite != null) _sprite.color = freezeTint;

        _effectRoutine = StartCoroutine(EffectRoutine(duration));
    }

    private IEnumerator EffectRoutine(float duration)
    {
        yield return new WaitForSeconds(duration);
        _effectRoutine = null;
        EndStunLike();
    }

    private void EndStunLike()
    {
        _sleeping = false;
        _pullVelocity = Vector2.zero;

        if (_sprite != null) _sprite.color = _baseColor;

        if (_controller.State == EnemyState.Atordoado && !_controller.IsTerminal)
            _controller.SetState(_stateBeforeEffect);
    }

    private void ApplyKnockback(Vector2 origin, float force)
    {
        var rb = _controller.Rb;
        if (rb == null) return;

        var stats = _controller.Data != null ? _controller.Data.stats : null;
        float resistance = stats != null ? Mathf.Clamp01(stats.knockbackResistance) : 0f;
        float weight = stats != null && stats.weight > 0f ? stats.weight : 1f;

        Vector2 dir = (Vector2)transform.position - origin;
        if (dir.sqrMagnitude < 0.0001f) dir = Vector2.right;

        float effective = force * (1f - resistance) / weight;
        if (effective > 0f) rb.AddForce(dir.normalized * effective, ForceMode2D.Impulse);
    }
}
